const invoices = $input.first().json.invoices || [];
const today = new Date();

return invoices.map(inv => {
  const sentDate = new Date(inv.sent_at);
  const daysOutstanding = Math.floor((today - sentDate) / (1000 * 60 * 60 * 24));

  let status;
  if (daysOutstanding < 7)  status = 'CURRENT';
  else if (daysOutstanding < 14) status = 'FOLLOW_UP';
  else if (daysOutstanding < 30) status = 'OVERDUE';
  else status = 'ESCALATE';

  return {
    json: {
      invoice_id: inv.id,
      client_name: inv.client_name,
      amount: inv.amount,
      sent_date: inv.sent_at,
      days_outstanding: daysOutstanding,
      due_date: inv.due_date,
      status,
      invoice_number: inv.invoice_number
    }
  };
}).filter(i => i.json.status !== 'CURRENT');

